// Why "protocol69": the projection is `66 XOR 7 = 69`, NOT `66 * 7`.
//
//   66 = the canonical Aeon RF-key packet's `prefixHash`  (the BROADCAST symbol,
//        radiated on the shared ambient carrier; see the GNOSIS-RFKEY/1 frame's
//        `prefixHash=66`).
//    7 = that same packet's `prefixLen`                   (the LOCAL FOIL operand
//        each receiver already holds; GNOSIS-RFKEY/1 `prefixLen=7`).
//
//   projection = broadcastSymbol XOR localFoilOperand
//              = 66 (0b1000010) XOR 7 (0b0000111)
//              = 69 (0b1000101)   -> the protocol name, wordName "sixty9".
//
// XOR (not multiply) is what makes it a teleport: a receiver admits only when its
// locally-held operand XORed against the broadcast symbol projects to exactly 69.
// A wrong/absent/tampered broadcast yields a projection != 69 and fails closed --
// no shared secret crosses the air, only the projection agreement does. The Lean
// contract is `gnosis-math/Gnosis/Protocol69IotaTeleport.lean` (`66 xor 7 = 69`,
// operand sourced from `canonicalAeonRFKeyPacket.prefixLen`). Wire magic "GN69" =
// ASCII (71,78,54,57).
pub const PROTOCOL69_SCHEMA_VERSION: &str = "gnosis.protocol69.v1";
pub const PROTOCOL69_NAME: &str = "protocol69";
pub const PROTOCOL69_WORD_NAME: &str = "sixty9";
pub const PROTOCOL69_OPERATOR: &str = "xor";
pub const MONSTER_NUMBER_SYMBOL_MAGIC: &str = "GNOSIS-MONSTER-NUMBER/1";

/// Broadcast symbol radiated on the ambient carrier = RF-key `prefixHash`.
pub const PROTOCOL69_BROADCAST_SYMBOL: u32 = 66;
/// Local FOIL operand each receiver holds = RF-key `prefixLen`. XORed with the
/// broadcast symbol to project the admission number (`66 ^ 7 = 69`).
pub const PROTOCOL69_LOCAL_FOIL_OPERAND: u32 = 7;
pub const PROTOCOL69_EXPECTED_PROJECTION: u32 = 69;

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69ProjectionEnvelope {
    pub schema_version: String,
    pub protocol: String,
    pub word_name: String,
    pub mode: String,
    pub magic: String,
    pub broadcast_symbol: u32,
    pub local_foil_operand: u32,
    pub operator: String,
    pub expected_projection: u32,
    pub ascii: String,
}

pub const fn protocol69_projection(broadcast_symbol: u32, local_foil_operand: u32) -> u32 {
    broadcast_symbol ^ local_foil_operand
}

pub fn build_protocol69_projection_envelope() -> Protocol69ProjectionEnvelope {
    let expected_projection =
        protocol69_projection(PROTOCOL69_BROADCAST_SYMBOL, PROTOCOL69_LOCAL_FOIL_OPERAND);
    debug_assert_eq!(expected_projection, PROTOCOL69_EXPECTED_PROJECTION);
    Protocol69ProjectionEnvelope {
        schema_version: PROTOCOL69_SCHEMA_VERSION.to_string(),
        protocol: PROTOCOL69_NAME.to_string(),
        word_name: PROTOCOL69_WORD_NAME.to_string(),
        mode: "monster-number".to_string(),
        magic: MONSTER_NUMBER_SYMBOL_MAGIC.to_string(),
        broadcast_symbol: PROTOCOL69_BROADCAST_SYMBOL,
        local_foil_operand: PROTOCOL69_LOCAL_FOIL_OPERAND,
        operator: PROTOCOL69_OPERATOR.to_string(),
        expected_projection,
        ascii: [
            MONSTER_NUMBER_SYMBOL_MAGIC.to_string(),
            format!("schemaVersion={PROTOCOL69_SCHEMA_VERSION}"),
            format!("protocol={PROTOCOL69_NAME}"),
            format!("wordName={PROTOCOL69_WORD_NAME}"),
            format!("broadcastSymbol={PROTOCOL69_BROADCAST_SYMBOL}"),
            format!("localFoilOperand={PROTOCOL69_LOCAL_FOIL_OPERAND}"),
            format!("operator={PROTOCOL69_OPERATOR}"),
            format!("expectedProjection={PROTOCOL69_EXPECTED_PROJECTION}"),
        ]
        .join(" "),
    }
}

pub fn validate_protocol69_projection_envelope(
    envelope: &Protocol69ProjectionEnvelope,
) -> Result<(), String> {
    if envelope.schema_version != PROTOCOL69_SCHEMA_VERSION {
        return Err(format!(
            "schemaVersion mismatch: expected {PROTOCOL69_SCHEMA_VERSION}, got {}",
            envelope.schema_version
        ));
    }
    if envelope.protocol != PROTOCOL69_NAME {
        return Err(format!(
            "protocol mismatch: expected {PROTOCOL69_NAME}, got {}",
            envelope.protocol
        ));
    }
    if envelope.word_name != PROTOCOL69_WORD_NAME {
        return Err(format!(
            "wordName mismatch: expected {PROTOCOL69_WORD_NAME}, got {}",
            envelope.word_name
        ));
    }
    if envelope.magic != MONSTER_NUMBER_SYMBOL_MAGIC {
        return Err(format!(
            "magic mismatch: expected {MONSTER_NUMBER_SYMBOL_MAGIC}, got {}",
            envelope.magic
        ));
    }
    if envelope.operator != PROTOCOL69_OPERATOR {
        return Err(format!(
            "operator mismatch: expected {PROTOCOL69_OPERATOR}, got {}",
            envelope.operator
        ));
    }
    let projection = protocol69_projection(envelope.broadcast_symbol, envelope.local_foil_operand);
    if projection != envelope.expected_projection {
        return Err(format!(
            "projection mismatch: {} xor {} = {}, envelope expected {}",
            envelope.broadcast_symbol,
            envelope.local_foil_operand,
            projection,
            envelope.expected_projection
        ));
    }
    if envelope.broadcast_symbol != PROTOCOL69_BROADCAST_SYMBOL
        || envelope.local_foil_operand != PROTOCOL69_LOCAL_FOIL_OPERAND
        || envelope.expected_projection != PROTOCOL69_EXPECTED_PROJECTION
    {
        return Err("protocol69 canonical operands do not match 66 xor 7 = 69".to_string());
    }
    Ok(())
}

