#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69WorkflowCertificate {
    pub certificate_id: String,
    pub network_theorem_id: String,
    pub eligibility_theorem_id: String,
    pub ack_theorem_id: String,
}

pub fn build_protocol69_workflow_certificate() -> Protocol69WorkflowCertificate {
    Protocol69WorkflowCertificate {
        certificate_id: PROTOCOL69_WORKFLOW_CERTIFICATE_ID.to_string(),
        network_theorem_id: PROTOCOL69_WORKFLOW_NETWORK_THEOREM_ID.to_string(),
        eligibility_theorem_id: PROTOCOL69_WORKFLOW_ELIGIBILITY_THEOREM_ID.to_string(),
        ack_theorem_id: PROTOCOL69_WORKFLOW_ACK_THEOREM_ID.to_string(),
    }
}

pub fn validate_protocol69_workflow_certificate(
    certificate: &Protocol69WorkflowCertificate,
) -> Result<(), String> {
    if certificate.certificate_id != PROTOCOL69_WORKFLOW_CERTIFICATE_ID {
        return Err(format!(
            "certificateId mismatch: expected {PROTOCOL69_WORKFLOW_CERTIFICATE_ID}, got {}",
            certificate.certificate_id
        ));
    }
    if certificate.network_theorem_id != PROTOCOL69_WORKFLOW_NETWORK_THEOREM_ID {
        return Err("network theorem id mismatch".to_string());
    }
    if certificate.eligibility_theorem_id != PROTOCOL69_WORKFLOW_ELIGIBILITY_THEOREM_ID {
        return Err("eligibility theorem id mismatch".to_string());
    }
    if certificate.ack_theorem_id != PROTOCOL69_WORKFLOW_ACK_THEOREM_ID {
        return Err("ack theorem id mismatch".to_string());
    }
    Ok(())
}

