#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct AsyncInputCollectionTask {
    pub task_id: String,
    pub kind: WorkflowWorkKind,
    pub executor: WorkflowExecutor,
    pub collected: bool,
    pub value_hash: Option<String>,
}

impl AsyncInputCollectionTask {
    pub fn pending(
        task_id: impl Into<String>,
        kind: WorkflowWorkKind,
        executor: WorkflowExecutor,
    ) -> Result<Self, String> {
        let task_id = normalize_nonempty(task_id.into(), "taskId")?;
        Ok(Self {
            task_id,
            kind,
            executor,
            collected: false,
            value_hash: None,
        })
    }

    pub fn collected(
        task_id: impl Into<String>,
        kind: WorkflowWorkKind,
        executor: WorkflowExecutor,
        value_hash: impl Into<String>,
    ) -> Result<Self, String> {
        let task_id = normalize_nonempty(task_id.into(), "taskId")?;
        let value_hash = normalize_nonempty(value_hash.into(), "valueHash")?;
        Ok(Self {
            task_id,
            kind,
            executor,
            collected: true,
            value_hash: Some(value_hash),
        })
    }

    pub fn collection_complete(&self) -> bool {
        self.collected
            && self
                .value_hash
                .as_deref()
                .is_some_and(|value_hash| !value_hash.trim().is_empty())
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct InputInferenceFoldWorkflow {
    pub workflow_id: String,
    pub x_input: AsyncInputCollectionTask,
    pub y_input: AsyncInputCollectionTask,
    pub x_inference_executor: WorkflowExecutor,
    pub y_inference_executor: WorkflowExecutor,
    pub z_executor: WorkflowExecutor,
    pub coordinator_free: bool,
    pub x_inference_acked: bool,
    pub y_inference_acked: bool,
    pub z_projection: Protocol69ProjectionEnvelope,
}

impl InputInferenceFoldWorkflow {
    pub fn inputs_collected(&self) -> bool {
        self.x_input.collection_complete() && self.y_input.collection_complete()
    }

    pub fn inferences_acked(&self) -> bool {
        self.x_inference_acked && self.y_inference_acked
    }

    pub fn compute_z_eligible(&self) -> bool {
        self.inputs_collected()
            && self.inferences_acked()
            && validate_protocol69_projection_envelope(&self.z_projection).is_ok()
    }

    pub fn may_dispatch_evaluation(&self) -> bool {
        self.compute_z_eligible()
    }

    pub fn may_self_evaluate(&self) -> bool {
        self.compute_z_eligible()
            && self.z_executor == WorkflowExecutor::CoordinatorSelf
            && self.coordinator_free
    }

    pub fn next_action(&self) -> Protocol69WorkflowAction {
        if !self.inputs_collected() {
            Protocol69WorkflowAction::DispatchInputCollection
        } else if !self.inferences_acked() {
            Protocol69WorkflowAction::LazyEvalWhenInputsReady
        } else if self.may_self_evaluate() {
            Protocol69WorkflowAction::SelfEvaluateWhenFree
        } else {
            Protocol69WorkflowAction::DispatchEvaluation
        }
    }

    pub fn validate(&self) -> Result<(), String> {
        normalize_nonempty(self.workflow_id.clone(), "workflowId")?;
        validate_protocol69_projection_envelope(&self.z_projection)
    }
}

