#[serde(tag = "ackKind", rename_all = "camelCase")]
pub enum Protocol69AgentAck {
    Input { ack: Protocol69InputAck },
    Lazy { receipt: Protocol69LazyAckReceipt },
}

impl Protocol69AgentAck {
    pub fn dispatch_id(&self) -> &str {
        match self {
            Self::Input { ack } => &ack.dispatch_id,
            Self::Lazy { receipt } => &receipt.dispatch_id,
        }
    }

    pub fn workflow_id(&self) -> &str {
        match self {
            Self::Input { ack } => &ack.workflow_id,
            Self::Lazy { receipt } => &receipt.workflow_id,
        }
    }

    pub fn executor(&self) -> WorkflowExecutor {
        match self {
            Self::Input { ack } => ack.task.executor,
            Self::Lazy { receipt } => receipt.executor,
        }
    }

    pub fn work_kind(&self) -> WorkflowWorkKind {
        match self {
            Self::Input { ack } => ack.task.kind,
            Self::Lazy { receipt } => receipt.work_kind,
        }
    }

    pub fn state(&self) -> LazyAckState {
        match self {
            Self::Input { ack } => ack.state,
            Self::Lazy { receipt } => receipt.state,
        }
    }

    pub fn validate(&self) -> Result<(), String> {
        match self {
            Self::Input { ack } => validate_protocol69_input_ack(ack),
            Self::Lazy { receipt } => validate_protocol69_lazy_ack_receipt(receipt),
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69InRoomAgent {
    pub agent_id: String,
    pub executor: WorkflowExecutor,
    pub skills: Vec<WorkflowWorkKind>,
}

impl Protocol69InRoomAgent {
    pub fn new(
        agent_id: impl Into<String>,
        executor: WorkflowExecutor,
        skills: Vec<WorkflowWorkKind>,
    ) -> Result<Self, String> {
        let agent_id = normalize_nonempty(agent_id.into(), "agentId")?;
        if skills.is_empty() {
            return Err("in-room agent requires at least one skill".to_string());
        }
        Ok(Self {
            agent_id,
            executor,
            skills,
        })
    }

    pub fn can_accept(&self, frame: &Protocol69WorkflowFrame) -> bool {
        self.executor == frame.executor && self.skills.contains(&frame.work_kind)
    }

    pub fn respond_to_frame(
        &self,
        frame: &Protocol69WorkflowFrame,
    ) -> Result<Protocol69AgentAck, String> {
        validate_protocol69_workflow_frame(frame)?;
        if !self.can_accept(frame) {
            return Err(format!(
                "agent {} cannot accept {:?}/{:?}",
                self.agent_id, frame.executor, frame.work_kind
            ));
        }

        let result_hash = deterministic_in_room_result_hash(&self.agent_id, frame);
        match frame.work_kind {
            WorkflowWorkKind::CollectBarcodeSupply
            | WorkflowWorkKind::CollectPingLatency
            | WorkflowWorkKind::CollectPlutoPreflight
            | WorkflowWorkKind::CacheMissInput
            | WorkflowWorkKind::ManualInput => {
                let task = AsyncInputCollectionTask::collected(
                    format!("{}:input", frame.dispatch_id),
                    frame.work_kind,
                    self.executor,
                    result_hash,
                )?;
                let ack = build_protocol69_input_ack(
                    frame.workflow_id.clone(),
                    frame.dispatch_id.clone(),
                    task,
                )?;
                Ok(Protocol69AgentAck::Input { ack })
            }
            WorkflowWorkKind::RunInferenceX
            | WorkflowWorkKind::RunInferenceY
            | WorkflowWorkKind::ComputeZ
            | WorkflowWorkKind::ForkjoinMcpInvocation
            | WorkflowWorkKind::CacheFill => {
                let receipt = build_protocol69_lazy_ack_receipt(frame, result_hash)?;
                Ok(Protocol69AgentAck::Lazy { receipt })
            }
        }
    }
}

