#[derive(Debug, Clone, Default)]
pub struct Protocol69DispatchQueueState {
    pending: VecDeque<Protocol69WorkflowFrame>,
    claimed: HashMap<String, Protocol69WorkflowFrame>,
    completed: Vec<Protocol69AgentAck>,
    rejected: u64,
}

impl Protocol69DispatchQueueState {
    pub fn summary(&self) -> Protocol69DispatchQueueSummary {
        Protocol69DispatchQueueSummary {
            schema_version: PROTOCOL69_DISPATCH_SUMMARY_SCHEMA_VERSION.to_string(),
            contract_id: PROTOCOL69_DISPATCH_SUMMARY_CONTRACT_ID.to_string(),
            pending: self.pending.len() as u64,
            claimed: self.claimed.len() as u64,
            completed: self.completed.len() as u64,
            rejected: self.rejected,
            timestamp_ms: protocol69_now_ms(),
        }
    }

    pub fn enqueue(
        &mut self,
        frame: Protocol69WorkflowFrame,
    ) -> Result<Protocol69DispatchQueueSummary, String> {
        validate_protocol69_workflow_frame(&frame)?;
        if self
            .pending
            .iter()
            .any(|pending| pending.dispatch_id == frame.dispatch_id)
            || self.claimed.contains_key(&frame.dispatch_id)
            || self
                .completed
                .iter()
                .any(|ack| ack.dispatch_id() == frame.dispatch_id)
        {
            return Err("dispatchId is already present in the in-room queue".to_string());
        }
        if self.pending.len().saturating_add(self.claimed.len()) >= PROTOCOL69_IN_ROOM_QUEUE_LIMIT {
            return Err(format!(
                "protocol69 in-room queue exceeds limit {PROTOCOL69_IN_ROOM_QUEUE_LIMIT}"
            ));
        }
        self.pending.push_back(frame);
        Ok(self.summary())
    }

    pub fn claim_for_agent(
        &mut self,
        agent: &Protocol69InRoomAgent,
    ) -> Result<Protocol69DispatchClaim, String> {
        normalize_nonempty(agent.agent_id.clone(), "agentId")?;
        let matching_index = self
            .pending
            .iter()
            .position(|frame| agent.can_accept(frame));
        let Some(index) = matching_index else {
            return Ok(Protocol69DispatchClaim {
                schema_version: PROTOCOL69_DISPATCH_CLAIM_SCHEMA_VERSION.to_string(),
                contract_id: PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID.to_string(),
                status: "idle".to_string(),
                agent_id: agent.agent_id.clone(),
                dispatch_id: None,
                frame: None,
                summary: self.summary(),
                projection: build_protocol69_projection_envelope(),
            });
        };

        let frame = self
            .pending
            .remove(index)
            .ok_or_else(|| "pending dispatch index disappeared".to_string())?;
        let dispatch_id = frame.dispatch_id.clone();
        self.claimed.insert(dispatch_id.clone(), frame.clone());
        Ok(Protocol69DispatchClaim {
            schema_version: PROTOCOL69_DISPATCH_CLAIM_SCHEMA_VERSION.to_string(),
            contract_id: PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID.to_string(),
            status: "claimed".to_string(),
            agent_id: agent.agent_id.clone(),
            dispatch_id: Some(dispatch_id),
            frame: Some(frame),
            summary: self.summary(),
            projection: build_protocol69_projection_envelope(),
        })
    }

    pub fn accept_ack(
        &mut self,
        ack: Protocol69AgentAck,
    ) -> Result<Protocol69DispatchQueueSummary, String> {
        ack.validate()?;
        let dispatch_id = ack.dispatch_id().to_string();
        let Some(frame) = self.claimed.get(&dispatch_id) else {
            self.rejected = self.rejected.saturating_add(1);
            return Err("dispatchId is not actively claimed".to_string());
        };
        if let Err(error) = validate_protocol69_agent_ack_matches_frame(frame, &ack) {
            self.rejected = self.rejected.saturating_add(1);
            return Err(error);
        }
        self.claimed.remove(&dispatch_id);
        self.completed.push(ack);
        Ok(self.summary())
    }
}

#[derive(Debug, Clone)]
pub struct Protocol69AntiqueueNetworkState {
    network_id: String,
    nodes: HashMap<String, Protocol69DispatchQueueState>,
}

impl Protocol69AntiqueueNetworkState {
    pub fn new(network_id: impl Into<String>) -> Result<Self, String> {
        Ok(Self {
            network_id: normalize_nonempty(network_id.into(), "networkId")?,
            nodes: HashMap::new(),
        })
    }

    pub fn register_node(&mut self, node_id: impl Into<String>) -> Result<(), String> {
        let node_id = normalize_nonempty(node_id.into(), "nodeId")?;
        self.nodes.entry(node_id).or_default();
        Ok(())
    }

    pub fn enqueue_on_node(
        &mut self,
        node_id: impl Into<String>,
        frame: Protocol69WorkflowFrame,
    ) -> Result<Protocol69AntiqueueNetworkSummary, String> {
        let node_id = normalize_nonempty(node_id.into(), "nodeId")?;
        let queue = self.nodes.entry(node_id).or_default();
        queue.enqueue(frame)?;
        Ok(self.summary())
    }

    pub fn claim_for_agent(
        &mut self,
        agent: &Protocol69InRoomAgent,
    ) -> Result<Protocol69NetworkDispatchClaim, String> {
        normalize_nonempty(agent.agent_id.clone(), "agentId")?;
        let mut node_ids = self.nodes.keys().cloned().collect::<Vec<_>>();
        node_ids.sort();

        for node_id in node_ids {
            let queue = self
                .nodes
                .get_mut(&node_id)
                .ok_or_else(|| "registered antiqueue node disappeared".to_string())?;
            let claim = queue.claim_for_agent(agent)?;
            if claim.status == "claimed" {
                return Ok(Protocol69NetworkDispatchClaim {
                    schema_version: PROTOCOL69_NETWORK_CLAIM_SCHEMA_VERSION.to_string(),
                    contract_id: PROTOCOL69_NETWORK_CLAIM_CONTRACT_ID.to_string(),
                    network_id: self.network_id.clone(),
                    status: "claimed".to_string(),
                    node_id: Some(node_id),
                    claim,
                    summary: self.summary(),
                });
            }
        }

        Ok(Protocol69NetworkDispatchClaim {
            schema_version: PROTOCOL69_NETWORK_CLAIM_SCHEMA_VERSION.to_string(),
            contract_id: PROTOCOL69_NETWORK_CLAIM_CONTRACT_ID.to_string(),
            network_id: self.network_id.clone(),
            status: "idle".to_string(),
            node_id: None,
            claim: Protocol69DispatchClaim {
                schema_version: PROTOCOL69_DISPATCH_CLAIM_SCHEMA_VERSION.to_string(),
                contract_id: PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID.to_string(),
                status: "idle".to_string(),
                agent_id: agent.agent_id.clone(),
                dispatch_id: None,
                frame: None,
                summary: Protocol69DispatchQueueState::default().summary(),
                projection: build_protocol69_projection_envelope(),
            },
            summary: self.summary(),
        })
    }

    pub fn accept_ack(
        &mut self,
        ack: Protocol69AgentAck,
    ) -> Result<Protocol69AntiqueueNetworkSummary, String> {
        ack.validate()?;
        let dispatch_id = ack.dispatch_id().to_string();
        let mut node_ids = self.nodes.keys().cloned().collect::<Vec<_>>();
        node_ids.sort();
        for node_id in node_ids {
            let Some(queue) = self.nodes.get_mut(&node_id) else {
                continue;
            };
            if queue.claimed.contains_key(&dispatch_id) {
                queue.accept_ack(ack)?;
                return Ok(self.summary());
            }
        }
        Err("dispatchId is not actively claimed in the antiqueue network".to_string())
    }

    pub fn summary(&self) -> Protocol69AntiqueueNetworkSummary {
        let mut node_ids = self.nodes.keys().cloned().collect::<Vec<_>>();
        node_ids.sort();
        let mut pending = 0_u64;
        let mut claimed = 0_u64;
        let mut completed = 0_u64;
        let mut rejected = 0_u64;
        let nodes = node_ids
            .into_iter()
            .filter_map(|node_id| {
                self.nodes.get(&node_id).map(|queue| {
                    let summary = queue.summary();
                    pending = pending.saturating_add(summary.pending);
                    claimed = claimed.saturating_add(summary.claimed);
                    completed = completed.saturating_add(summary.completed);
                    rejected = rejected.saturating_add(summary.rejected);
                    Protocol69AntiqueueNodeSummary { node_id, summary }
                })
            })
            .collect();

        Protocol69AntiqueueNetworkSummary {
            schema_version: PROTOCOL69_NETWORK_SUMMARY_SCHEMA_VERSION.to_string(),
            contract_id: PROTOCOL69_NETWORK_SUMMARY_CONTRACT_ID.to_string(),
            network_id: self.network_id.clone(),
            nodes,
            pending,
            claimed,
            completed,
            rejected,
            timestamp_ms: protocol69_now_ms(),
            certificate: build_protocol69_workflow_certificate(),
            projection: build_protocol69_projection_envelope(),
        }
    }
}

pub fn build_protocol69_input_ack(
    workflow_id: impl Into<String>,
    dispatch_id: impl Into<String>,
    task: AsyncInputCollectionTask,
) -> Result<Protocol69InputAck, String> {
    if !task.collection_complete() {
        return Err("input ack requires a collected task with a nonempty valueHash".to_string());
    }
    Ok(Protocol69InputAck {
        schema_version: PROTOCOL69_INPUT_ACK_SCHEMA_VERSION.to_string(),
        contract_id: PROTOCOL69_INPUT_ACK_CONTRACT_ID.to_string(),
        certificate: build_protocol69_workflow_certificate(),
        workflow_id: normalize_nonempty(workflow_id.into(), "workflowId")?,
        dispatch_id: normalize_nonempty(dispatch_id.into(), "dispatchId")?,
        task,
        state: LazyAckState::Completed,
        action: Protocol69WorkflowAction::AckInput,
        projection: build_protocol69_projection_envelope(),
    })
}

pub fn build_protocol69_pluto_preflight_ack(
    workflow_id: impl Into<String>,
    dispatch_id: impl Into<String>,
    observation: &Protocol69PlutoPreflightObservation,
) -> Result<Protocol69InputAck, String> {
    validate_protocol69_pluto_preflight_observation(observation)?;
    let task = AsyncInputCollectionTask::collected(
        "input-pluto-preflight",
        WorkflowWorkKind::CollectPlutoPreflight,
        WorkflowExecutor::LocalAgent,
        protocol69_pluto_preflight_value_hash(observation)?,
    )?;
    build_protocol69_input_ack(workflow_id, dispatch_id, task)
}

pub fn validate_protocol69_pluto_preflight_observation(
    observation: &Protocol69PlutoPreflightObservation,
) -> Result<(), String> {
    normalize_nonempty(observation.bridge_url.clone(), "bridgeUrl")?;
    normalize_nonempty(observation.pluto_uri.clone(), "plutoUri")?;
    normalize_nonempty(observation.framework.clone(), "framework")?;
    normalize_nonempty(observation.iio_attr.clone(), "iioAttr")?;
    normalize_nonempty(observation.iio_writedev.clone(), "iioWritedev")?;
    if !observation.ok {
        return Err("Pluto preflight observation must be ok before ack".to_string());
    }
    if observation.tx_enabled {
        return Err("Pluto preflight input ack requires fail-closed txEnabled=false".to_string());
    }
    Ok(())
}

pub fn protocol69_pluto_preflight_value_hash(
    observation: &Protocol69PlutoPreflightObservation,
) -> Result<String, String> {
    validate_protocol69_pluto_preflight_observation(observation)?;
    let mut hasher = DefaultHasher::new();
    observation.bridge_url.hash(&mut hasher);
    observation.pluto_uri.hash(&mut hasher);
    observation.ok.hash(&mut hasher);
    observation.tx_enabled.hash(&mut hasher);
    observation.framework.hash(&mut hasher);
    observation.iio_attr.hash(&mut hasher);
    observation.iio_writedev.hash(&mut hasher);
    Ok(format!("pluto-preflight:siphash:{:016x}", hasher.finish()))
}

pub fn protocol69_arguments_hash(value: &serde_json::Value) -> Result<String, String> {
    let canonical = serde_json::to_string(value).map_err(|error| error.to_string())?;
    let mut hasher = DefaultHasher::new();
    canonical.hash(&mut hasher);
    Ok(format!("args:siphash:{:016x}", hasher.finish()))
}

pub fn protocol69_cache_fill_result_hash(
    cache_key: &str,
    answer_tokens: &[u32],
    answer_text: &str,
    provenance: &str,
) -> Result<String, String> {
    let cache_key = normalize_nonempty(cache_key.to_string(), "cacheKey")?;
    let provenance = normalize_nonempty(provenance.to_string(), "provenance")?;
    if answer_tokens.is_empty() && answer_text.trim().is_empty() {
        return Err("cache fill requires answerTokens or answerText".to_string());
    }
    let mut hasher = DefaultHasher::new();
    cache_key.hash(&mut hasher);
    answer_tokens.hash(&mut hasher);
    answer_text.hash(&mut hasher);
    provenance.hash(&mut hasher);
    Ok(format!("cache-fill:siphash:{:016x}", hasher.finish()))
}

