pub fn validate_protocol69_cache_miss_input(
    input: &Protocol69CacheMissInput,
) -> Result<(), String> {
    if input.schema_version != PROTOCOL69_CACHE_MISS_SCHEMA_VERSION {
        return Err("cache miss schemaVersion mismatch".to_string());
    }
    if input.contract_id != PROTOCOL69_CACHE_MISS_CONTRACT_ID {
        return Err("cache miss contractId mismatch".to_string());
    }
    validate_protocol69_workflow_certificate(&input.certificate)?;
    if input.theorem_id != PROTOCOL69_CACHE_MISS_THEOREM_ID {
        return Err("cache miss theorem id mismatch".to_string());
    }
    normalize_nonempty(input.workflow_id.clone(), "workflowId")?;
    normalize_nonempty(input.dispatch_id.clone(), "dispatchId")?;
    normalize_nonempty(input.cache_key.clone(), "cacheKey")?;
    normalize_nonempty(input.model.clone(), "model")?;
    normalize_nonempty(input.qspec.clone(), "qspec")?;
    normalize_nonempty(input.source_node.clone(), "sourceNode")?;
    if input.tokens.is_empty() {
        return Err("cache miss input requires at least one token".to_string());
    }
    validate_protocol69_projection_envelope(&input.projection)
}

