    #[test]
    fn in_room_queue_dispatches_input_collection_and_accepts_agent_ack() {
        let mut workflow = canonical_taskrabbit_workflow();
        workflow.y_input = AsyncInputCollectionTask::pending(
            "input-ping-1-1-1-1",
            WorkflowWorkKind::CollectPingLatency,
            WorkflowExecutor::LocalAgent,
        )
        .unwrap();
        let frame = build_protocol69_workflow_frame(
            &workflow,
            Protocol69WorkflowAction::DispatchInputCollection,
        )
        .expect("missing ping input dispatches");
        let agent = Protocol69InRoomAgent::new(
            "usb-antenna-local-1",
            WorkflowExecutor::LocalAgent,
            vec![WorkflowWorkKind::CollectPingLatency],
        )
        .unwrap();
        let mut queue = Protocol69DispatchQueueState::default();

        let summary = queue.enqueue(frame.clone()).expect("enqueue frame");
        assert_eq!(summary.pending, 1);

        let claim = queue.claim_for_agent(&agent).expect("claim frame");
        assert_eq!(claim.status, "claimed");
        assert_eq!(
            claim.dispatch_id.as_deref(),
            Some(frame.dispatch_id.as_str())
        );
        assert_eq!(claim.summary.pending, 0);
        assert_eq!(claim.summary.claimed, 1);

        let ack = agent
            .respond_to_frame(claim.frame.as_ref().expect("claimed frame"))
            .expect("agent responds");
        match &ack {
            Protocol69AgentAck::Input { ack } => {
                validate_protocol69_input_ack(ack).expect("input ack validates");
                assert_eq!(ack.dispatch_id, frame.dispatch_id);
                assert_eq!(ack.task.executor, WorkflowExecutor::LocalAgent);
                assert_eq!(ack.task.kind, WorkflowWorkKind::CollectPingLatency);
            }
            Protocol69AgentAck::Lazy { .. } => panic!("input collection must return input ack"),
        }

        let summary = queue.accept_ack(ack).expect("accept ack");
        assert_eq!(summary.claimed, 0);
        assert_eq!(summary.completed, 1);
        assert_eq!(summary.rejected, 0);
    }

