    // ── 32-byte wire envelope: round-trip fidelity ──

    /// decode(encode(e)) = e across a sampled value sweep including the
    /// extremes of every field — the Rust mirror of the Lean field
    /// round-trip (`Gnosis/Protocol69Wire.lean::envelope_roundtrip`).
    #[test]
    fn wire_envelope_roundtrip() {
        let canonical = Protocol69WireEnvelope::for_prefix(0xDEAD_BEEF_CAFE_F00D, 4096, 5, 7);
        assert_eq!(
            decode_protocol69_envelope(&encode_protocol69_envelope(&canonical)).unwrap(),
            canonical
        );

        // Deterministic sweep: a multiplicative congruential walk over
        // the field domains, plus the extremes.
        let mut x: u64 = 0x9E37_79B9_7F4A_7C15;
        for _ in 0..256 {
            x = x.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
            let broadcast = (x >> 7) as u32;
            let operand = (x >> 23) as u32;
            let envelope = Protocol69WireEnvelope {
                broadcast_symbol: broadcast,
                local_foil_operand: operand,
                projection: protocol69_projection(broadcast, operand),
                prefix_hash: x,
                prefix_len: (x >> 11) as u32,
                layer_lo: (x >> 3) as u16,
                layer_hi: (x >> 37) as u16,
            };
            let decoded =
                decode_protocol69_envelope(&encode_protocol69_envelope(&envelope)).unwrap();
            assert_eq!(decoded, envelope);
        }
        let extremes = Protocol69WireEnvelope {
            broadcast_symbol: u32::MAX,
            local_foil_operand: u32::MAX,
            projection: 0,
            prefix_hash: u64::MAX,
            prefix_len: u32::MAX,
            layer_lo: u16::MAX,
            layer_hi: u16::MAX,
        };
        assert_eq!(
            decode_protocol69_envelope(&encode_protocol69_envelope(&extremes)).unwrap(),
            extremes
        );
    }

    /// The parser never misreads what the writer meant: wrong length,
    /// wrong magic, and an internally inconsistent projection all
    /// refuse instead of yielding a "mostly parsed" envelope.
    #[test]
    fn wire_envelope_refuses_misreads() {
        let envelope = Protocol69WireEnvelope::for_prefix(1, 2, 3, 4);
        let bytes = encode_protocol69_envelope(&envelope);

        assert!(decode_protocol69_envelope(&bytes[..31]).is_err(), "short frame");
        let mut long = bytes.to_vec();
        long.push(0);
        assert!(decode_protocol69_envelope(&long).is_err(), "long frame");

        let mut bad_magic = bytes;
        bad_magic[0] ^= 0xFF;
        assert!(decode_protocol69_envelope(&bad_magic).is_err(), "magic");

        let mut bad_projection = bytes;
        bad_projection[12] ^= 0x01;
        assert!(
            decode_protocol69_envelope(&bad_projection).is_err(),
            "projection inconsistent with broadcast ^ operand"
        );
    }

    /// The canonical constructor cannot produce a refusable frame, and
    /// its projection is the protocol's 66 ^ 7 = 69.
    #[test]
    fn wire_envelope_canonical_is_valid() {
        let envelope = Protocol69WireEnvelope::for_prefix(0, 0, 0, 0);
        assert_eq!(envelope.projection, PROTOCOL69_EXPECTED_PROJECTION);
        assert!(decode_protocol69_envelope(&encode_protocol69_envelope(&envelope)).is_ok());
    }
